{
  "competency_groups": [
    {
      "code": "C1",
      "title": "Some Basic Concepts of Chemistry",
      "description": "Equip learners with tools to understand the working of chemistry, develop conceptual foundations for real-life application, and enable representation at macroscopic, molecular, and symbolic levels.",
      "competencies": [
        "Apply mole concept and stoichiometric calculations to determine percentage composition and molar masses",
        "Represent chemical phenomena using laws of combination and Dalton's atomic theory across different scales",
        "Identify patterns in measurement uncertainty and properties of matter"
      ],
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry"
    },
    {
      "code": "C2",
      "title": "Structure of Atom",
      "description": "Develop understanding of atomic structure through historical models and quantum mechanical principles to explain chemical behavior.",
      "competencies": [
        "Trace the development from sub-atomic particle discovery to Bohr's model for hydrogen atom",
        "Apply quantum mechanical model concepts to describe electronic arrangements in atoms"
      ],
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom"
    },
    {
      "code": "C3",
      "title": "Classification of Elements and Periodicity in Properties",
      "description": "Enable learners to classify elements based on periodic laws, electronic configurations, and identify trends across s-, p-, d-, f- blocks.",
      "competencies": [
        "Utilize modern periodic law and nomenclature rules for elements with atomic number > 100",
        "Correlate electronic configuration types (s, p, d, f) with element classification in the periodic table"
      ],
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties"
    },
    {
      "code": "C4",
      "title": "Chemical Bonding and Molecular Structure",
      "description": "Foster ability to analyze bonding mechanisms using Kossel-Lewis, VBT, MOT, and VSEPR theories to predict molecular structures.",
      "competencies": [
        "Differentiate between ionic/electrovalent bonds and covalent interactions via Lewis approach",
        "Predict bond parameters and molecular geometry using hybridization concepts and VSEPR theory"
      ],
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure"
    },
    {
      "code": "C5",
      "title": "Thermodynamics",
      "description": "Prepare learners to analyze energy changes, spontaneity, and equilibrium in chemical processes using thermodynamic terms.",
      "competencies": [
        "Calculate enthalpy changes for various reaction types and interpret calorimetry data (∆U and ∆H)",
        "Evaluate the spontaneity of reactions based on Gibbs Energy change and equilibrium conditions"
      ],
      "unit_name": "Thermodynamics",
      "chapter_name": "Chemical Thermodynamics"
    }
  ]
}
